import redis
from typing import Dict, Any

class RedisClient:
    def __init__(self, host: str, port: int, password: str):
        self.host = host
        self.port = port
        self.password = password
        self.redis_clients = {}

    def get_client(self) -> redis.Redis:
        if self.host not in self.redis_clients:
            self.redis_clients[self.host] = redis.Redis(
                host=self.host,
                port=self.port,
                password=self.password,
                ssl=True  # Prevent unencrypted connection
            )
        return self.redis_clients[self.host]

    def set(self, key: str, value: Any, ttl: int):
        client = self.get_client()
        client.set(key, value, ex=ttl)

    def get(self, key: str) -> Any:
        client = self.get_client()
        return client.get(key)

    def delete(self, key: str):
        client = self.get_client()
        client.delete(key)


class Microservice:
    def __init__(self, redis_host: str, redis_port: int, redis_password: str):
        self.redis_client = RedisClient(redis_host, redis_port, redis_password)

    def store_user_data(self, user_id: str, data: Dict[str, Any]):
        session_token = data['session_token']
        api_key = data['api_key']

        # Store sensitive data with appropriate TTL
        self.redis_client.set(f'session:{user_id}', session_token, ttl=3600)  # 1 hour
        self.redis_client.set(f'api_key:{user_id}', api_key, ttl=86400)  # 24 hours

    def get_user_data(self, user_id: str):
        session_token = self.redis_client.get(f'session:{user_id}')
        api_key = self.redis_client.get(f'api_key:{user_id}')

        return {
            'session_token': session_token,
            'api_key': api_key
        }